import{gsap,ScrollTrigger,SplitText,ScrambleTextPlugin,DrawSVGPlugin,MotionPathPlugin}from"gsap/all";import Lenis from"lenis";gsap.registerPlugin(ScrollTrigger,SplitText,ScrambleTextPlugin,DrawSVGPlugin,MotionPathPlugin);export function gsapController(){let lenis=new Lenis;gsap.ticker.add(time=>{lenis.raf(700*time)}),gsap.ticker.lagSmoothing(0),gsap.from(".banner_con img",{scale:1.3,duration:3,ease:"power4.out"});let bannerTextsST=new SplitText(["header p","nav ul li a",".banner_info p"],{type:"lines, lines",linesClass:"line"}),bannerTextsTL,bannerImg,middleImg;gsap.timeline().from(bannerTextsST.lines,{y:200,opacity:0,ease:"back.out",stagger:{each:.1}}),gsap.timeline({scrollTrigger:{start:"top top",scrub:!0}}).to(".banner_con img",{objectPosition:"0% 100%"}),gsap.timeline({scrollTrigger:{start:"top top",end:"bottom center",scrub:!0}}).to(".middle_img img",{objectPosition:"0% 100%"});let middleTextsST=new SplitText([".middle_con h2",".middle_con p"],{type:"lines, lines",linesClass:"line"}),middleTextsTL;gsap.timeline({scrollTrigger:{trigger:".middle_con",start:"top center"}}).from(middleTextsST.lines,{y:50,opacity:0,ease:"back.out",stagger:{each:.1}});let mainTextsST=new SplitText([".founded_info section h3",".founded_info section p",".foundational_guiding h2",".foundational_guiding p",".foundational_guiding ul"],{type:"lines, lines",linesClass:"line"});gsap.from(mainTextsST.lines,{y:50,opacity:0,ease:"back.out",stagger:{each:.1},scrollTrigger:{trigger:".main_con",start:"top center"}})}